      if (now - _hdgAt <= 450 && (nx * _hdgX + ny * _hdgY) > 0) {
        nx = nx * 0.6 + _hdgX * 0.4; ny = ny * 0.6 + _hdgY * 0.4;
        const _bm = Math.hypot(nx, ny) || 1; nx /= _bm; ny /= _bm;
      }
      _hdgX = nx; _hdgY = ny; _hdgAt = now;
      gridDX = nx * _m; gridDY = ny * _m;
