    utilityActiveTarget = null;
    utilityNoPathCount = 0;
    utilityArrivalWaitStart = 0;
    utilitySessionStartTime = 0;
    utilityLastProgressDist = Infinity;
    utilityLastProgressTime = 0;
    finishUtilityState();
