    hideoutSkipExistingPortalUntil = Date.now() + HIDEOUT_SKIP_OLD_PORTALS_AFTER_COMPLETE_MS;
    mapCompleteFlowStartTime = Date.now();
    mapCompleteRetreatReachedAt = 0;
