    mapCompletePortalInteractAttempts = 0;
    mapCompleteOpenPortalLastAt = 0;
    mapCompleteOpenPortalAttempts = 0;
    mapCompleteLastHp = 0;
    mapCompleteDangerDetectedAt = 0;
    mapCompleteDangerEscapeAttempts = 0;
    mapCompleteDangerLastEscapeAt = 0;
